func retryWithJitter(req *http.Request, maxRetries int) (*http.Response, error) {
    for attempt := 0; attempt < maxRetries; attempt++ {
        resp, err := client.Do(req)
        if err == nil && resp.StatusCode != 503 {
            return resp, nil
        }
        jitter := time.Duration(rand.Intn(200)) * time.Millisecond
        time.Sleep((1<<attempt)*100*time.Millisecond + jitter)
    }
    return nil, fmt.Errorf("auth: max retries exceeded")
}

